1	'use client';
2	
3	import {
4	    Anchor,
5	    Box,
6	    Button,
7	    Checkbox,
8	    Flex,
9	    RangeSlider,
10	    Switch,
11	    Table,
12	    Text,
13	    TextInput,
14	    Title,
15	    Tooltip,
16	} from '@mantine/core';
17	import { IconSortAscending, IconSortDescending } from '@tabler/icons-react';
18	import type { GameDayType } from 'prisma/zod/schemas/models/GameDay.schema';
19	import { useState } from 'react';
20	
21	import { PlayerTimeline } from '@/components/PlayerTimeline/PlayerTimeline';
22	import { PlayerWDLChart } from '@/components/PlayerWDLChart/PlayerWDLChart';
23	import { SendEmailForm } from '@/components/SendEmailForm/SendEmailForm';
24	import type { PlayerDataType } from '@/types';
25	import type { SendEmailProxy } from '@/types/actions/SendEmail';
26	
27	export interface Props {
28	    players: PlayerDataType[];
29	    gameDay: GameDayType;
30	    sendEmail: SendEmailProxy;
31	}
32	
33	export const PlayerList = ({ players, gameDay, sendEmail }: Props) => {
34	    const [sortBy, setSortBy] = useState<keyof PlayerDataType | null>('name');
35	    const [sortOrder, setSortOrder] = useState<'asc' | 'desc'>('asc');
36	    const [filter, setFilter] = useState('');
37	    const [active, setActive] = useState(true);
38	    const [replyRange, setReplyRange] = useState<[number, number]>([0, gameDay.id]);
39	    const [selectedPlayers, setSelectedPlayers] = useState<PlayerDataType[]>([]);
40	    const [modalOpened, setModalOpened] = useState(false);
41	
42	    const handleSort = (key: keyof PlayerDataType) => {
43	        if (sortBy === key) {
44	            setSortOrder((prev) => (prev === 'asc' ? 'desc' : 'asc'));
45	        } else {
46	            setSortBy(key);
47	            setSortOrder('asc');
48	        }
49	    };
50	
51	    const handleSelectPlayer = (player: PlayerDataType) => {
52	        if (selectedPlayers.includes(player)) {
53	            setSelectedPlayers((prev) => prev.filter((p) => player !== p));
54	        } else {
55	            setSelectedPlayers((prev) => [...prev, player]);
56	        }
57	    };
58	
59	    const filteredPlayers = players?.filter((player) => {
60	        const searchTerm = filter.toLowerCase();
61	        const nameMatches = player.name?.toLowerCase().includes(searchTerm) ?? false;
62	        const emailMatches = [player.accountEmail, ...player.extraEmails.map((playerEmail) => playerEmail.email)]
63	            .filter((playerEmail): playerEmail is string => !!playerEmail)
64	            .some((playerEmail) => playerEmail.toLowerCase().includes(searchTerm));
65	        const searchResult = nameMatches || emailMatches;
66	
67	        return searchResult && (!active || player.finished === null);
68	    }) || [];
69	
70	    const playersRepliedSince = filteredPlayers.filter((player) => {
71	        if (!player.lastResponded) {
72	            return (replyRange[1] === gameDay.id);
73	        }
74	        else {
75	            const repliedAfter = (gameDay.id - player.lastResponded) >= replyRange[0];
76	            const repliedBefore = (gameDay.id - player.lastResponded) <= replyRange[1];
77	
78	            return repliedAfter && repliedBefore;
79	        }
80	    });
81	
82	    const sortedPlayers = playersRepliedSince ? [...playersRepliedSince].sort((a, b) => {
83	        if (!sortBy) return 0;
84	
85	        const aValue = a[sortBy];
86	        const bValue = b[sortBy];
87	
88	        if (typeof aValue === 'number' || typeof bValue === 'number') {
89	            /* v8 ignore next 3 -- defensive fallback when a numeric sort field is unexpectedly nullish */
90	            const naValue = aValue as number || 0;
91	            const nbValue = bValue as number || 0;
92	
93	            return sortOrder === 'asc' ? naValue - nbValue : nbValue - naValue;
94	        }
95	
96	        if (typeof aValue === 'string' && typeof bValue === 'string') {
97	            return sortOrder === 'asc' ?
98	                aValue.localeCompare(bValue) :
99	                bValue.localeCompare(aValue);
100	        }
101	
102	        if (aValue instanceof Date && bValue instanceof Date) {
103	            return sortOrder === 'asc' ?
104	                aValue.getTime() - bValue.getTime() :
105	                bValue.getTime() - aValue.getTime();
106	        }
107	
108	        return 0;
109	    }) :
110	        /* v8 ignore next -- filter always returns an array, so this fallback is a defensive backstop */
111	        [];
112	
113	    /**
114	     * Human-readable label describing whether we are showing only active players
115	     * or both active and former players, used in the main title text.
116	     */
117	    const activeStatusLabel = active ? 'Active Players' : 'Active and Former Players';
118	
119	    /** Formats a RangeSlider thumb value as a human-readable week count label. */
120	    const rangeSliderLabel = (value: number) => `${value} weeks`;
121	    /**
122	     * Updates the reply-range filter from the RangeSlider.
123	     * @param range - A [min, max] tuple of weeks-ago values matching the heading text.
124	     */
125	    const handleRangeChange = (range: [number, number]) => setReplyRange(range);
126	    /** Opens the send-email modal for the currently selected players. */
127	    const handleOpenEmailModal = () => setModalOpened(true);
128	    /** Closes the send-email modal. */
129	    const handleCloseEmailModal = () => setModalOpened(false);
130	
131	    return (
132	        <Box>
133	            <Title order={1}>{sortedPlayers.length} {activeStatusLabel}</Title>
134	            <Title order={3}>who last responded between {replyRange[0]} and {replyRange[1]} weeks ago</Title>
135	            <TextInput
136	                mt={20}
137	                mb={20}
138	                placeholder="Search players"
139	                value={filter}
140	                onChange={(event) => setFilter(event.currentTarget.value)}
141	            />
142	            <Switch
143	                mt={20}
144	                mb={20}
145	                checked={active}
146	                onChange={(event) => setActive(event.currentTarget.checked)}
147	                color="blue"
148	                label="Active"
149	            />
150	            <Text size="sm">Last Response Range</Text>
151	            <RangeSlider
152	                label={rangeSliderLabel}
153	                min={0}
154	                max={gameDay.id}
155	                step={1}
156	                value={replyRange}
157	                onChange={handleRangeChange}
158	            />
159	            <Checkbox
160	                mt={20}
161	                mb={20}
162	                label="Select All"
163	                checked={selectedPlayers.length === sortedPlayers.length && sortedPlayers.length > 0}
164	                onChange={(event) => {
165	                    if (event.currentTarget.checked) {
166	                        setSelectedPlayers(sortedPlayers);
167	                    } else {
168	                        setSelectedPlayers([]);
169	                    }
170	                }}
171	            />
172	            <Text size="sm">Selected: {selectedPlayers.length}</Text>
173	            <Tooltip label="Send an email to the selected players">
174	                <Button
175	                    disabled={selectedPlayers.length === 0}
176	                    onClick={handleOpenEmailModal}
177	                >
178	                    Send Email...
179	                </Button>
180	            </Tooltip>
181	            <SendEmailForm
182	                players={selectedPlayers.map(({ id, name, accountEmail, extraEmails }) => ({
183	                    id,
184	                    name,
185	                    accountEmail,
186	                    extraEmails,
187	                }))}
188	                opened={modalOpened}
189	                onClose={handleCloseEmailModal}
190	                onSendEmail={sendEmail}
191	            />
192	
193	            <Table mt={20}>
194	                <Table.Thead>
195	                    <Table.Tr>
196	                        <Table.Th>
197	                            Select
198	                        </Table.Th>
199	                        <Table.Th style={{ cursor: 'pointer' }} onClick={() => handleSort('name')}>
200	                            <Flex align="center" gap="xs">
201	                                Name
202	                                {sortBy === 'name' ? (sortOrder === 'asc' ? <IconSortAscending /> : <IconSortDescending />) : ''}
203	                            </Flex>
204	                        </Table.Th>
205	                        <Table.Th>
206	                            W-D-L
207	                        </Table.Th>
208	                        <Table.Th>
209	                            Timeline
210	                        </Table.Th>
211	                    </Table.Tr>
212	                </Table.Thead>
213	                <Table.Tbody>
214	                    {sortedPlayers.map((player) => (
215	                        <Table.Tr key={player.id}>
216	                            <Table.Td>
217	                                <Checkbox
218	                                    checked={selectedPlayers.includes(player)}
219	                                    onChange={() => handleSelectPlayer(player)}
220	                                />
221	                            </Table.Td>
222	                            <Table.Td>
223	                                <Anchor href={`/footy/player/${encodeURIComponent(player.id || "")}`}>
224	                                    {player.name}
225	                                </Anchor>
226	                            </Table.Td>
227	                            <Table.Td>
228	                                <PlayerWDLChart player={player} />
229	                            </Table.Td>
230	                            <Table.Td>
231	                                <PlayerTimeline player={player} currentGameId={gameDay.id} />
232	                            </Table.Td>
233	                        </Table.Tr>
234	                    ))}
235	                </Table.Tbody>
236	            </Table>
237	        </Box>
238	    );
239	};
240

