        it('throws InternalError when MAIL_GRAPH_CLIENT_SECRET is undefined', async () => {
            getSecretsMock.mockReturnValue({
                MAIL_FROM_NAME: 'Mailer',
                MAIL_FROM_ADDRESS: 'mailer@example.com',
